import{_ as r,c as a,o as t,ag as p}from"./chunks/framework.D4Vqf8I7.js";const c=JSON.parse('{"title":"Эльбрус","description":"","frontmatter":{},"headers":[],"relativePath":"docs/wi/elbrus.md","filePath":"docs/wi/elbrus.md","lastUpdated":1779893064000}'),s={name:"docs/wi/elbrus.md"};function l(o,e,u,i,d,n){return t(),a("div",null,e[0]||(e[0]=[p('<h1 id="эльбрус" tabindex="-1">Эльбрус <a class="header-anchor" href="#эльбрус" aria-label="Permalink to &quot;Эльбрус&quot;">​</a></h1><h2 id="«мцст»-выпустила-эмулятор-qemu‐e2k-на-базе-qemu-10-1-1-для-архитектуры-«эльбрус»-e2k" tabindex="-1">«МЦСТ» выпустила эмулятор qemu‑e2k (на базе QEMU 10.1.1) для архитектуры «Эльбрус» (e2k) <a class="header-anchor" href="#«мцст»-выпустила-эмулятор-qemu‐e2k-на-базе-qemu-10-1-1-для-архитектуры-«эльбрус»-e2k" aria-label="Permalink to &quot;«МЦСТ» выпустила эмулятор qemu‑e2k (на базе QEMU 10.1.1) для архитектуры «Эльбрус» (e2k)&quot;">​</a></h2><p><a href="https://habr.com/ru/news/981424/" target="_blank" rel="noreferrer">https://habr.com/ru/news/981424/</a></p><p><img src="https://habrastorage.org/r/w1560/getpro/habr/upload_files/880/bdd/323/880bdd32399ab95e46cef4619b7bc151.png" alt=""></p><p><a href="https://git.openelbrus.ru/mcst/qemu" target="_blank" rel="noreferrer">https://git.openelbrus.ru/mcst/qemu</a></p><p><a href="https://dev.mcst.ru/download/" target="_blank" rel="noreferrer">https://dev.mcst.ru/download/</a></p><p>В конце декабря 2025 года АО «МЦСТ» (Московский Центр Спарк (SPARС) Технологии) — разработчик процессоров «Эльбрус» и операционной системы «Эльбрус Линукс») выпустила в открытый доступ эмулятор qemu‑e2k (на базе QEMU 10.1.1) для архитектуры «Эльбрус» (e2k).</p><p>Эмулятор qemu‑e2k обеспечивает возможность, используя операционную систему семейства Linux, запускать прикладные программы для операционных систем семейства Linux в машинных кодах «Эльбрус» (e2k) на ПК с архитектурой x86-64.</p><p><img src="https://habrastorage.org/r/w1560/getpro/habr/upload_files/289/855/339/2898553399bedad9be565292e40bd1d1.png" alt=""></p><p>Предполагаемые сценарии использования эмулятора QEMU:</p><ul><li><p>запуск готовых программ в машинных кодах процессоров «Эльбрус» для ознакомления с возможностями архитектуры и программной экосистемы, без использования физического оборудования с процессорами «Эльбрус»;</p></li><li><p>запуск компилятора для архитектуры Эльбрус в нативном окружении (в двоичных кодах процессоров «Эльбрус»), но на процессорах с архитектурой x86-64, без использования кросс‑компиляции;</p></li><li><p>локальная или распределённая сборка на серверах с архитектурой x86-64 дистрибутивов операционных систем в машинных кодах процессоров Эльбрус, также без использования кросс‑компиляции.</p></li></ul><p>QEMU — это универсальное средство эмуляции различных процессорных архитектур, а также средство запуска виртуальных машин (гипервизор). Для каждой целевой архитектуры предусматривается два варианта эмулятора:</p><ul><li><p>qemu‑system — эмулятор уровня системы, позволяющий запустить целую операционную систему, такую как Linux;</p></li><li><p>qemu‑user (он же qemu‑linux, он же просто qemu) — эмулятор уровня приложений, позволяющий запустить гостевое приложение внутри хозяйской операционной системы (Linux).</p></li></ul><p>В текущей реализации QEMU от «МЦСТ» поддержка архитектуры «Эльбрус» реализована во втором варианте — на уровне прикладных программ Linux. В российской компании ведётся работа над эмулятором уровня системы.</p><p>В сентябре 2025 года состоялся релиз пакетного менеджера RPM 6.0. Примечательно, что это первый выпуск проекта RPM, в который добавлена поддержка архитектуры «Эльбрус» (e2k).</p><p><img src="https://habrastorage.org/r/w1560/getpro/habr/upload_files/6ae/d2f/d76/6aed2fd7641c5820fbe64f936cb75a1c.png" alt=""></p>',16)]))}const h=r(s,[["render",l]]);export{c as __pageData,h as default};
